async (params, browser) => {
  // Open Trello
  await browser.open('https://trello.com')

  // Let Trello load
  await browser.wait(2000)

  // Create card via Trello API
  const result = await browser.evaluate(`const params = new URLSearchParams({ idList: params.list_id, name: params.name }); const desc = params.description; if (desc) params.set('desc', desc); const due = params.due_date; if (due) params.set('due', due); const resp = await fetch('/1/cards?' + params.toString(), { method: 'POST', credentials: 'same-origin' }); if (!resp.ok) { const err = await resp.text(); throw new Error('Create card failed: ' + resp.status + ' ' + err); } const card = await resp.json(); return { success: true, id: card.id, name: card.name, url: card.shortUrl || card.url }`)

  return result
}
